import{_ as s,C as o,o as e,c as E,a5 as n,b as p,w as t,a as l,E as i,a4 as A}from"./chunks/framework.gGRxziV4.js";const m=JSON.parse('{"title":"四类评估与纵深防御","description":"","frontmatter":{},"headers":[],"relativePath":"06-Agent评估/03-四类评估与纵深防御.md","filePath":"06-Agent评估/03-四类评估与纵深防御.md","lastUpdated":1774228824000}'),B={name:"06-Agent评估/03-四类评估与纵深防御.md"};function d(h,a,g,u,c,C){const r=o("Mermaid");return e(),E("div",null,[a[1]||(a[1]=n('<h1 id="四类评估与纵深防御" tabindex="-1">四类评估与纵深防御 <a class="header-anchor" href="#四类评估与纵深防御" aria-label="Permalink to &quot;四类评估与纵深防御&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 6 模块的第 3 章。</p></blockquote><p>四类 Agent 各有评估策略——但单一评估有漏洞，必须纵深防御。</p><hr><h2 id="四类-agent-的评估" tabindex="-1">四类 Agent 的评估 <a class="header-anchor" href="#四类-agent-的评估" aria-label="Permalink to &quot;四类 Agent 的评估&quot;">​</a></h2><h3 id="coding-agent" tabindex="-1">Coding Agent <a class="header-anchor" href="#coding-agent" aria-label="Permalink to &quot;Coding Agent&quot;">​</a></h3><p>最易评估——代码能编译、测试能通过、结果可复现。</p><p>评估维度：功能正确性（测试通过率）、代码质量（lint 评分、复杂度）、安全性（漏洞扫描）、性能（运行时间、内存使用）。</p><p>评估方法：SWE-Bench 等标准基准测试 + 自定义单元测试 + 集成测试。代码评分器是主力——编译检查、测试执行、lint 扫描。</p><h3 id="对话-agent" tabindex="-1">对话 Agent <a class="header-anchor" href="#对话-agent" aria-label="Permalink to &quot;对话 Agent&quot;">​</a></h3><p>评估难度中等——回答质量主观性强。</p><p>评估维度：准确性（事实是否正确）、相关性（是否回答了用户的问题）、完整性（是否覆盖所有方面）、安全性（是否有不当内容）。</p><p>评估方法：模型评分器是主力——用评分模型判断回答质量。人工抽样验证评分器准确性。</p><h3 id="研究-agent" tabindex="-1">研究 Agent <a class="header-anchor" href="#研究-agent" aria-label="Permalink to &quot;研究 Agent&quot;">​</a></h3><p>评估难度高——研究质量和深度难以量化。</p><p>评估维度：覆盖面（是否找到所有相关信息）、来源质量（引用是否可靠）、分析深度（是否有洞察）、报告结构（是否清晰易读）。</p><p>评估方法：混合——代码检查格式和来源链接有效性，模型评估分析质量，人类做最终验收。</p><h3 id="computer-use-agent" tabindex="-1">Computer Use Agent <a class="header-anchor" href="#computer-use-agent" aria-label="Permalink to &quot;Computer Use Agent&quot;">​</a></h3><p>评估难度最高——需要操作真实界面。</p><p>评估维度：任务完成率、操作效率（步骤数）、错误恢复能力、UI 理解准确性。</p><p>评估方法：端到端测试——给定任务描述，在真实环境中执行并检查最终状态。截图对比 + 状态检查。</p><hr><h2 id="瑞士奶酪模型" tabindex="-1">瑞士奶酪模型 <a class="header-anchor" href="#瑞士奶酪模型" aria-label="Permalink to &quot;瑞士奶酪模型&quot;">​</a></h2>',23)),(e(),p(A,null,{default:t(()=>[i(r,{id:"mermaid-67",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E8%BE%93%E5%87%BA%5D%20--%3E%20B%5B%E7%AC%AC%E4%B8%80%E5%B1%82%3A%20%E4%BB%A3%E7%A0%81%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E5%85%A8%E8%A6%86%E7%9B%96%3Cbr%2F%3E%E6%A0%BC%E5%BC%8F%2F%E8%AF%AD%E6%B3%95%2F%E6%B5%8B%E8%AF%95%5D%0A%20%20%20%20B%20--%3E%7C%E9%80%9A%E8%BF%87%7C%20C%5B%E7%AC%AC%E4%BA%8C%E5%B1%82%3A%20%E6%A8%A1%E5%9E%8B%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E6%8A%BD%E6%A0%B710-20%25%3Cbr%2F%3E%E8%AF%AD%E4%B9%89%2F%E9%80%BB%E8%BE%91%5D%0A%20%20%20%20C%20--%3E%7C%E9%80%9A%E8%BF%87%7C%20D%5B%E7%AC%AC%E4%B8%89%E5%B1%82%3A%20%E4%BA%BA%E7%B1%BB%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E5%85%B3%E9%94%AE%E8%8A%82%E7%82%B9%3Cbr%2F%3E%E6%9C%80%E7%BB%88%E9%AA%8C%E6%94%B6%5D%0A%20%20%20%20D%20--%3E%7C%E9%80%9A%E8%BF%87%7C%20E%5B%E7%AC%AC%E5%9B%9B%E5%B1%82%3A%20%E7%94%A8%E6%88%B7%E5%8F%8D%E9%A6%88%3Cbr%2F%3E%E6%8C%81%E7%BB%AD%E6%94%B6%E9%9B%86%5D%0A%20%20%20%20B%20-.-%3E%7C%E6%BC%8F%E8%BF%87%E8%AF%AD%E4%B9%89%E9%97%AE%E9%A2%98%7C%20F%5B%E6%BC%8F%E6%B4%9EA%5D%0A%20%20%20%20C%20-.-%3E%7C%E6%BC%8F%E8%BF%87%E4%B8%BB%E8%A7%82%E5%88%A4%E6%96%AD%7C%20G%5B%E6%BC%8F%E6%B4%9EB%5D%0A%20%20%20%20D%20-.-%3E%7C%E6%BC%8F%E8%BF%87%E9%95%BF%E5%B0%BE%E5%9C%BA%E6%99%AF%7C%20H%5B%E6%BC%8F%E6%B4%9EC%5D%0A%20%20%20%20F%20--%3E%7C%E8%A2%AB%E4%B8%8B%E4%B8%80%E5%B1%82%E8%A6%86%E7%9B%96%7C%20G%0A%20%20%20%20G%20--%3E%7C%E8%A2%AB%E4%B8%8B%E4%B8%80%E5%B1%82%E8%A6%86%E7%9B%96%7C%20H%0A%20%20%20%20H%20--%3E%7C%E8%A2%AB%E7%94%A8%E6%88%B7%E5%8F%8D%E9%A6%88%E5%8F%91%E7%8E%B0%7C%20E%0A"})]),fallback:t(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=n(`<blockquote><p>💡 <strong>图解：</strong> 每层评估都有盲区——像瑞士奶酪叠在一起，一层的洞被另一层盖住，整体防御远比单层可靠。</p></blockquote><p>单一评估就像一片瑞士奶酪——有漏洞。多层评估叠在一起，漏洞互相覆盖，整体防御更可靠。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[代码评分器] → 漏洞 A</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[模型评分器] → 覆盖漏洞 A，但有漏洞 B</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[人类评分器] → 覆盖漏洞 B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>每一层评估都有自己的盲区：代码评分器判断不了语义正确性，模型评分器可能有评分偏见，人类评分器可能有主观偏差。但三层叠在一起，各自的盲区被其他层覆盖。</p><h3 id="纵深防御实践" tabindex="-1">纵深防御实践 <a class="header-anchor" href="#纵深防御实践" aria-label="Permalink to &quot;纵深防御实践&quot;">​</a></h3><p><strong>第一层：代码评分器（全覆盖）</strong>——格式检查、语法验证、测试执行、安全扫描。每个输出都过一遍，成本近零。</p><p><strong>第二层：模型评分器（抽样）</strong>——对代码评分器通过的输出做语义检查。不需要每次都跑——随机抽样 10-20% 做深度评估。</p><p><strong>第三层：人类评分器（关键节点）</strong>——高价值输出的最终验收、评分器校准、边界案例处理。</p><p><strong>第四层：用户反馈（持续）</strong>——真实用户的使用反馈。最真实但有延迟。</p><hr><h2 id="评估的边界" tabindex="-1">评估的边界 <a class="header-anchor" href="#评估的边界" aria-label="Permalink to &quot;评估的边界&quot;">​</a></h2><p>评估不是万能的。有些问题评估发现不了：</p><p><strong>分布外问题</strong>：评估数据集只能覆盖已知场景。在未知场景中 Agent 可能失败，但评估不会检测到。</p><p><strong>对抗性输入</strong>：恶意用户可能构造特殊输入绕过评估。</p><p><strong>长期退化</strong>：评估通常是快照式的。Agent 可能在两次评估之间退化（比如模型更新后）。</p><p><strong>价值观和伦理</strong>：很难用自动化评估判断。</p><p>应对方法：持续评估（不是一次性而是持续运行）、对抗性测试（主动寻找边界案例）、监控（生产环境中的行为追踪）。</p><hr><h2 id="实践建议" tabindex="-1">实践建议 <a class="header-anchor" href="#实践建议" aria-label="Permalink to &quot;实践建议&quot;">​</a></h2><p>从代码评分器开始——成本最低效果最明显。逐步增加模型评分器覆盖软性指标。人类评分器只在关键节点使用。</p><p>评估数据集要持续更新——新的失败模式应该被加入评估集。评估结果要可视化——趋势比绝对值更重要。建立评估文化——每次发现 Bug 都问&quot;为什么评估没检测到&quot;。</p><hr><h2 id="评估漂移-当评估体系本身需要被评估" tabindex="-1">评估漂移：当评估体系本身需要被评估 <a class="header-anchor" href="#评估漂移-当评估体系本身需要被评估" aria-label="Permalink to &quot;评估漂移：当评估体系本身需要被评估&quot;">​</a></h2><p>评估体系不是一成不变的。随着模型能力提升，两个问题会自然出现：</p><p><strong>评估饱和</strong>：当所有测试用例通过率都接近 100%，评估体系就从&quot;能力测试&quot;退化为&quot;回归测试&quot;——只能告诉你&quot;没有退步&quot;，无法衡量&quot;进步了多少&quot;。</p><p><strong>评估偏移</strong>：模型行为模式变化导致评分器给出不准确的分数。经典案例：评分器期望 <code>96.1249911</code>，模型输出 <code>96.12</code> 被扣分——实际是评分器太僵化。</p><p><strong>应对策略：</strong></p><ul><li>定期审查评估结果分布——分数方差趋近于零说明评估已失效</li><li>每次模型升级后人工抽检 5-10% 结果</li><li>保留评估历史数据，排查通过率突变原因</li></ul><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>四类 Agent 评估难度递增：Coding &lt; 对话 &lt; 研究 &lt; Computer Use</li><li>瑞士奶酪模型：多层评估叠在一起漏洞互相覆盖</li><li>纵深防御：代码（全覆盖）→ 模型（抽样）→ 人类（关键）→ 用户反馈</li><li>评估的边界：分布外、对抗性、长期退化、价值观</li><li>持续评估比一次性评估更重要</li></ul><hr><p><strong>上一章</strong>: <a href="./02-评分器体系.html">评分器体系</a> | <strong>下一章</strong>: <a href="./04-从零构建.html">从零构建</a></p>`,33))])}const _=s(B,[["render",d]]);export{m as __pageData,_ as default};
